import React, {useState} from 'react';
import Project from './../components/Project'

function ProjectList({name, desc}){
  const [isprojects, setProjects] = useState([
    {
      id: 1,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/booklandia-site.png",
    },
    {
      id: 2,
      name: "TESDA Women's Center",
      desc: "Website",
      img: "img/works/twc.png",
    },
    {
      id: 3,
      name: "Booklandia",
      desc: "Website",
      img: "img/works/fun-run.png",
    },
  ])

  return(
    <div>
    {isprojects.map(project => (
      <Project />
    ))}
    </div>
  );
}
export default ProjectList
